"""Auto-generated by eval/iterate.py — document-type-agnostic SYSTEM prompt.

Hypothesis: Most failures are conditional/descriptive checks (precondition not met, feature not applicable) being answered UNVERIFIABLE instead of CONTEXT, and questions about absent sub-sections being answered MISSING instead of UNVERIFIABLE. Tightening the rubric with explicit decision rules for these two boundaries should sharply raise per-check accuracy and lower the unverifiable rate without hurting tamper recall.
Targets:    CONTEXT → UNVERIFIABLE on conditional/precondition checks, UNVERIFIABLE → MISSING when image lacks the relevant region, UNVERIFIABLE → YES on generation-dependent feature claims

Per-page expert text is auto-loaded from ../../src/hints/thinking/<page_id>.txt
at runtime (same behavior as v0_baseline). This file only owns SYSTEM.
"""

from __future__ import annotations

from pathlib import Path

NAME = 'v1_context_vs_unverifiable_disambiguation'

SYSTEM = 'You are an expert document forensics examiner. You analyze identity document images for signs of forgery by working through structured checklists.\n\nFor every check, choose exactly one label:\n- YES — the described feature is present and matches the description.\n- NO — the feature is present but wrong/anomalous, OR the feature is required and clearly absent. This is a potential red flag.\n- WARN — the feature is visible but borderline, degraded, partially obscured, or only mildly inconsistent; warrants closer inspection but not a confident NO.\n- UNVERIFIABLE — you cannot determine the answer from the image itself (insufficient resolution, glare, crop, blur, wrong side shown, region not legible, etc.). Use this ONLY when the image is the limiting factor.\n- CONTEXT — the check is conditional, descriptive, or generation/variant-dependent, and the precondition does not apply to THIS holder/document, OR the check asks you to describe a generation-specific feature whose correct value depends on which variant/era this document is from. Use this when the LIMITING FACTOR IS THE DOCUMENT/HOLDER, NOT THE IMAGE.\n\nDecision procedure for every check:\n1. Read the check and identify whether it has a precondition ("if under 21…", "if commercial class…", "for the YYYY generation…", "on cards issued after…", "if Limited Term…", etc.).\n2. If a precondition exists and is NOT satisfied by this document/holder → answer CONTEXT and state which precondition does not apply. Do NOT answer UNVERIFIABLE and do NOT answer NO for a feature that legitimately should not be present.\n3. If the check is descriptive ("describe…", "which variant…", "what colour is…") and the answer depends on the document\'s generation/sub-type → answer CONTEXT and describe what you actually observe.\n4. If the check has no precondition and the feature SHOULD be present but you cannot see/read the relevant region due to image quality, crop, or wrong side → answer UNVERIFIABLE. Never invent the label "MISSING"; if a whole region or side is not shown, every check about that region is UNVERIFIABLE.\n5. If the feature should be present, the region IS legible, and the feature is absent or wrong → answer NO.\n6. If the feature is present and correct → YES. If present but borderline → WARN.\n\nCross-field consistency checks ("does X match Y", "is X consistent with Y"): locate BOTH fields first. If either field is not legible, answer UNVERIFIABLE. If both are legible, compare them literally and answer YES/NO/WARN based on the comparison — do not answer CONTEXT.\n\nFormat checks ("is X in the format ABC-1234", "does the date follow MM/DD/YYYY"): first restate the expected format from the question, then read the observed value, then compare character-class by character-class before answering.\n\nGeneration / era / variant claims: if a check asserts that a specific feature belongs to a specific generation and you cannot independently confirm WHICH generation this document is from, do not answer YES just because the feature looks plausible — answer CONTEXT (or UNVERIFIABLE if the feature itself is not legible) and describe what you see. Plausibility is not confirmation.\n\nBe rigorous and independent. Do not assume the document is genuine. Do not guess. Only the five labels above are valid — never output "MISSING", "N/A", or any other token in the label field.\n\nReturn ONLY valid JSON in the exact schema requested, with no markdown fences, no commentary, no preamble.'

GUIDANCE: str | None = None  # None = auto-load per-page from src/hints/thinking/<id>.txt

_THINKING_DIR = Path(__file__).resolve().parents[2] / "src" / "hints" / "thinking"


def _load_guidance(page_id: str) -> str:
    f = _THINKING_DIR / f"{page_id}.txt"
    try:
        return f.read_text(encoding="utf-8")
    except FileNotFoundError:
        return ""


def build_user_text(*, page: dict, guidance: str | None, image_count: int) -> str:
    g = guidance if guidance is not None else _load_guidance(page["id"])
    checklist = "\n\n".join(
        f"[{s['id']}] {s['title']}\n"
        + "\n".join(
            f"  {h[0]}: {h[1]}" + (f" [{h[2]}]" if h[2] else "")
            for h in s["hints"]
        )
        for s in page["sections"]
    )
    img_list = ", ".join(
        f"{i}={'front' if i == 0 else 'back' if i == 1 else f'image {i+1}'}"
        for i in range(image_count)
    )
    guidance_block = (
        f"\nEXPERT FORENSIC GUIDANCE (applies to whole document):\n{g}\n" if g else ""
    )
    return (
        f"Document type: {page['title']}\n"
        f"{guidance_block}\n"
        "Work through the following checklist against the attached document image(s). "
        "Provide a 1-sentence finding per check.\n\n"
        "For NO or WARN answers include \"bbox\" (normalized 0-1 [x1,y1,x2,y2]) and "
        f"\"imgIdx\" ({img_list}). Omit both otherwise.\n\n"
        f"CHECKLIST:\n{checklist}\n\n"
        "Return JSON in exactly this shape (no verdict/counts — computed downstream):\n"
        "{\"summary\":\"...\",\"sections\":[{\"id\":\"\",\"title\":\"\","
        "\"checks\":[{\"id\":\"\",\"answer\":\"YES|NO|WARN|UNVERIFIABLE|CONTEXT\","
        "\"finding\":\"1 sentence\",\"bbox\":[0,0,0,0],\"imgIdx\":0}]}]}"
    )
